from math import gcd
def a(n):
    if n == 0: return 0
    B1, B2 = 2**(n-1), 2**n
    return 2*sum(1 for i in range(B1) for j in range(i+1, B2, 2) if i&j == 0 and gcd(i,j) == 1)
print([a(n) for n in range(15)]) # _Michael S. Branicky_, Jun 11 2026

